      "table.puf": ";; qualified-only import target; defines its own `length` (module-\n;; private shadow of the prelude) and exports an ADT -- constructors\n;; travel through provide/require like any other top-level name\n(provide size lookup classify Scalar Vec2)\n(define-type Datum\n  (Scalar Int)\n  (Vec2 Int Int))\n(define (length l) 1000000)\n(define (size t) (length t))\n(define (lookup t k)\n  (match t\n    ['() #f]\n    [`((,k2 . ,v) . ,rest) (if (eq? k k2) v (lookup rest k))]))\n(define (classify [d : Datum]) : Sym\n  (match d\n    [(Scalar _) 'scalar]\n    [(Vec2 _ _) 'vec]))\n",
      "util.puf": "(provide twice len compose)\n(define (twice f x) (f (f x)))\n(define (len l) (if (null? l) 0 (+ 1 (len (cdr l)))))\n(define (compose f g) (lambda (x) (f (g x))))\n",
