    code: ";; stress: globals, closures, match, ADTs, hashes, sets, symbols, strings, loops\n(define version 'v1)\n(define (make-counter)\n  (let ([n 0])\n    (lambda () (begin (set! n (+ n 1)) n))))\n(define c (make-counter))\n(c) (c)\n(println (c))                          ;; 3\n\n(define h (make-hash))\n(hash-set! h 'a 1)\n(hash-set! h 'b 2)\n(println (hash-ref h 'b))              ;; 2\n(println (hash-count h))               ;; 2\n(hash-remove! h 'a)\n(println (hash-has-key? h 'a))         ;; #f\n\n(define s (make-set))\n(let loop ([i 0])\n  (when (< i 100) (set-add! s (remainder i 7)) (loop (+ i 1))))\n(println (set-count s))                ;; 7\n\n(define (sum-list xs)\n  (match xs\n    ['() 0]\n    [(cons hd tl) (+ hd (sum-list tl))]))\n(println (sum-list (list 1 2 3 4 5)))  ;; 15\n\n(define-type Expr\n  (Num Int)\n  (Add Expr Expr)\n  (Mul Expr Expr))\n(define (eval-expr [e : Expr]) : Int\n  (match e\n    [(Num n) n]\n    [(Add a b) (+ (eval-expr a) (eval-expr b))]\n    [(Mul a b) (* (eval-expr a) (eval-expr b))]))\n(println (eval-expr (Add (Mul (Num 3) (Num 4)) (Add (Num 1) (Num 2)))))  ;; 15\n\n(println (string-append \"hello, \" \"world\"))\n(println (vector 1 (list 2 3) 'sym #t))\n(println version)\n(let fib ([n 20])\n  (if (< n 2) n (+ (fib (- n 1)) (fib (- n 2)))))\n",
